import { createTool } from '@mastra/core/tools'
import { z } from 'zod'
import { redactPii } from '../lib/pii'
import { searchDocs } from '../lib/vector-store'

export default createTool({
  id: 'search_knowledge',
  description:
    'Semantic search over indexed Linear issues and Notion pages. Use this BEFORE falling back to live Linear/Notion lookups or web search.',
  inputSchema: z.object({
    query: z.string().describe('A search query to find relevant company knowledge'),
    topK: z.number().min(1).max(10).default(5).describe('Number of results to return'),
  }),
  outputSchema: z.object({
    results: z.array(z.object({
      content: z.string(),
      source: z.string(),
      title: z.string().optional(),
      url: z.string().optional(),
      score: z.number().optional(),
    })),
  }),
  execute: async (inputData) => {
    const { query, topK } = inputData
    const hits = await searchDocs(query, topK)
    const results = hits.map((row) => ({
      content: redactPii(String(row.content)),
      source: String(row.source),
      title: row.title ? String(row.title) : undefined,
      url: row.url ? String(row.url) : undefined,
      score: row.score ? Number(row.score) : undefined,
    }))
    return { results }
  },
})

import { createTool } from '@mastra/core/tools'
import { z } from 'zod'
import { indexDoc } from '../lib/vector-store'

export default createTool({
  id: 'index_document',
  description:
    'Adds a document to the knowledge corpus by chunking and embedding it.',
  inputSchema: z.object({
    source: z.string(),
    content: z.string(),
  }),
  execute: async (inputData) => {
    const { source, content } = inputData
    const chunks = await indexDoc({ source, content })
    return { chunks, source }
  },
})

import { openai } from '@ai-sdk/openai'
import { createClient } from '@libsql/client'
import { embed, embedMany } from 'ai'

const db = createClient({ url: process.env.LIBSQL_URL ?? 'file:knowledge.db' })
const embeddingModel = openai.embedding('text-embedding-3-small')

export interface Doc {
  source: string
  content: string
}

export function chunkText(text: string, size = 1000, overlap = 200): string[] {
  const out: string[] = []
  for (let i = 0; i < text.length; i += size - overlap) {
    const slice = text.slice(i, i + size).trim()
    if (slice) {
      out.push(slice)
    }
  }
  return out
}

async function ensureSchema(): Promise<void> {
  await db.execute(
    'CREATE TABLE IF NOT EXISTS docs (id INTEGER PRIMARY KEY AUTOINCREMENT, source TEXT, content TEXT, embedding F32_BLOB(1536))'
  )
}

export async function indexDoc(doc: Doc): Promise<number> {
  await ensureSchema()
  const chunks = chunkText(doc.content)
  const { embeddings } = await embedMany({ model: embeddingModel, values: chunks })
  for (let i = 0; i < chunks.length; i++) {
    await db.execute({
      sql: 'INSERT INTO docs (source, content, embedding) VALUES (?, ?, vector32(?))',
      args: [doc.source, chunks[i], JSON.stringify(embeddings[i])],
    })
  }
  return chunks.length
}

export async function searchDocs(query: string, topK: number) {
  await ensureSchema()
  const { embedding } = await embed({ model: embeddingModel, value: query })
  const result = await db.execute({
    sql: 'SELECT source, content, vector_distance_cos(embedding, vector32(?)) AS distance FROM docs ORDER BY distance ASC LIMIT ?',
    args: [JSON.stringify(embedding), topK],
  })
  return result.rows
}

const PATTERNS: [RegExp, string][] = [
  [/[\w.+-]+@[\w-]+\.[\w.-]+/g, '[redacted-email]'],
  [/\b(?:\+?\d{1,2}[\s-]?)?(?:\(\d{3}\)|\d{3})[\s-]?\d{3}[\s-]?\d{4}\b/g, '[redacted-phone]'],
  [/\b\d{3}-\d{2}-\d{4}\b/g, '[redacted-ssn]'],
  [/\b(?:\d[ -]?){13,16}\b/g, '[redacted-card]'],
  [/\b(?:sk|pk|api|key)[-_][A-Za-z0-9]{16,}\b/g, '[redacted-key]'],
]

export function redactPii(text: string): string {
  return PATTERNS.reduce((acc, [pattern, replacement]) => acc.replace(pattern, replacement), text)
}

import { createWorkflow, createStep } from '@mastra/core/workflows'
import { z } from 'zod'
import { chunkText, indexDoc } from '../lib/vector-store'

const fetchContent = createStep({
  id: 'fetch-content',
  description: 'Fetches content from a URL',
  inputSchema: z.object({
    url: z.string().url(),
  }),
  outputSchema: z.object({
    source: z.string(),
    content: z.string(),
  }),
  execute: async ({ inputData }) => {
    const response = await fetch(inputData.url)
    if (!response.ok) {
      throw new Error(`Failed to fetch content: ${response.status} ${response.statusText}`)
    }
    const content = await response.text()
    return { source: inputData.url, content }
  },
})

const chunkContent = createStep({
  id: 'chunk-content',
  description: 'Splits content into chunks for embedding',
  inputSchema: z.object({
    source: z.string(),
    content: z.string(),
  }),
  outputSchema: z.object({
    source: z.string(),
    chunks: z.array(z.string()),
  }),
  execute: async ({ inputData }) => {
    const chunks = chunkText(inputData.content)
    return { source: inputData.source, chunks }
  },
})

const embedAndStore = createStep({
  id: 'embed-and-store',
  description: 'Embeds chunks and stores them in the vector database',
  inputSchema: z.object({
    source: z.string(),
    chunks: z.array(z.string()),
  }),
  outputSchema: z.object({
    source: z.string(),
    chunksStored: z.number(),
  }),
  execute: async ({ inputData }) => {
    const chunksStored = await indexDoc({
      source: inputData.source,
      content: inputData.chunks.join('\n\n'),
    })
    return { source: inputData.source, chunksStored }
  },
})

export const indexKnowledgeWorkflow = createWorkflow({
  id: 'index-knowledge-workflow',
  inputSchema: z.object({
    url: z.string().url(),
  }),
  outputSchema: z.object({
    source: z.string(),
    chunksStored: z.number(),
  }),
})
  .then(fetchContent)
  .then(chunkContent)
  .then(embedAndStore)

indexKnowledgeWorkflow.commit()

import { Memory } from '@mastra/memory'

export default new Memory({
  options: {
    lastMessages: 10,
  },
})
